class ITBudgetTracker:
 def __init__(self, annual_budget):
 self.annual_budget = annual_budget
 self.spent = 0
 self.allocated = 0
 self.projects = []

 def add_project(self, name, cost, quarter):
 project = {
 'name': name,
 'cost': cost,
 'quarter': quarter,
 'status': 'planned'
 }
 self.projects.append(project)
 self.allocated += cost

 def get_utilization(self):
 return (self.spent / self.annual_budget) * 100

 def get_variance(self):
 return self.annual_budget - self.spent

